import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

const Login = ({ onLoginSuccess }) => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({ email: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);
        try {
            const res = await api.post('/auth/login', formData);
            if (res.data?.token) {
                localStorage.setItem('token', res.data.token);
                // Menyimpan role sesuai data dari DB ('Perusahaan' atau 'Pelamar')
                localStorage.setItem('role', res.data.user?.role);

                alert('Login Berhasil!');
                if (onLoginSuccess) onLoginSuccess();
                navigate('/');
            }
        } catch (err) {
            setError(err.response?.data?.message || 'Email atau password salah!');
        } finally {
            setLoading(false);
        }
    };

    const styles = {
        container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: '#120902', padding: '1rem' },
        card: { width: '100%', maxWidth: '400px', background: '#0c0a09', padding: '2rem', borderRadius: '12px', border: '1px solid #262626' },
        title: { color: '#fef3c7', marginBottom: '1.5rem', textAlign: 'center' },
        label: { display: 'block', color: '#fef3c7', marginBottom: '0.5rem', fontSize: '14px' },
        input: { width: '100%', padding: '10px', marginBottom: '1rem', borderRadius: '8px', border: '1px solid #404040', background: '#171717', color: '#fff', boxSizing: 'border-box' },
        btn: { width: '100%', padding: '10px', background: '#ea580c', border: 'none', borderRadius: '8px', color: '#fff', fontWeight: 'bold', cursor: 'pointer' },
        errorAlert: { color: '#fca5a5', marginBottom: '1rem', textAlign: 'center', fontSize: '13px' }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <h2 style={styles.title}>Masuk Akun</h2>
                {error && <div style={styles.errorAlert}>{error}</div>}
                <form onSubmit={handleLogin}>
                    <label style={styles.label}>Email</label>
                    <input type="email" name="email" value={formData.email} onChange={handleChange} style={styles.input} required />
                    <label style={styles.label}>Password</label>
                    <input type="password" name="password" value={formData.password} onChange={handleChange} style={styles.input} required />
                    <button type="submit" style={styles.btn} disabled={loading}>{loading ? 'Memverifikasi...' : 'Masuk Akun'}</button>
                </form>
            </div>
        </div>
    );
};

export default Login;
